function debounce(fn, delay, options = {}) {
  const { leading = false, trailing = true } = options;
  let timer = null;
  let lastArgs = null;
  let leadingCalled = false;

  const debounced = function (...args) {
    // 如果 trailing 为 false 且不打算执行，直接返回
    if (!trailing && !leading) return;

    const callNow = leading && !timer && !leadingCalled;

    if (timer) {
      clearTimeout(timer);
      timer = null;
    }

    if (callNow) {
      leadingCalled = true;
      fn.apply(this, args);
    } else {
      lastArgs = [this, args];
    }

    if (trailing) {
      timer = setTimeout(() => {
        timer = null;
        leadingCalled = false;
        if (lastArgs) {
          const [ctx, a] = lastArgs;
          lastArgs = null;
          fn.apply(ctx, a);
        }
      }, delay);
    }
  };

  debounced.cancel = function () {
    if (timer) {
      clearTimeout(timer);
      timer = null;
    }
    lastArgs = null;
    leadingCalled = false;
  };

  debounced.flush = function () {
    if (timer && lastArgs) {
      clearTimeout(timer);
      timer = null;
      const [ctx, a] = lastArgs;
      lastArgs = null;
      leadingCalled = false;
      fn.apply(ctx, a);
    }
  };

  return debounced;
}
```

**用法举例：**

```javascript
// 搜索框防抖，用户停止输入 300ms 后才发起请求
const search = debounce(
  (keyword) => fetch(`/api/search?q=${keyword}`),
  300
);

input.addEventListener('input', (e) => search(e.target.value));

// 需要立即取消时
search.cancel();

// 立即执行最后一次 pending 调用
search.flush();
```

**三个要点：**

1. **基本机制** — 每次触发重置计时器，只在连续触发停止后执行一次。
2. **leading / trailing 模式** — `leading: true` 让第一次触发立即执行，`trailing: false` 停止尾部执行。默认 trailing，即"等停稳后才执行"。
3. **cancel / flush** — 清理计时器和强制落盘，避免回调泄漏或状态残留。

