```typescript
// 定义一组类型，每个类型都有一个共同的字面量字段（discriminant）
type Shape =
  | { kind: "circle"; radius: number }
  | { kind: "rectangle"; width: number; height: number }
  | { kind: "triangle"; base: number; height: number };

// TypeScript 会根据这个共同字段自动收窄类型
function area(s: Shape): number {
  switch (s.kind) {
    case "circle":
      // 这里 s 自动收窄为 { kind: "circle"; radius: number }
      return Math.PI * s.radius ** 2;
    case "rectangle":
      // s 收窄为 { kind: "rectangle"; width: number; height: number }
      return s.width * s.height;
    case "triangle":
      // s 收窄为 { kind: "triangle"; base: number; height: number }
      return (s.base * s.height) / 2;
  }
}

// 如果新增一个类型但忘记处理，可以用 exhaustive check 兜住
function areaSafe(s: Shape): number {
  switch (s.kind) {
    case "circle":
      return Math.PI * s.radius ** 2;
    case "rectangle":
      return s.width * s.height;
    case "triangle":
      return (s.base * s.height) / 2;
    default:
      // s 在这里的类型是 never，如果上面没覆盖全，编译会报错
      const _exhaustive: never = s;
      return _exhaustive;
  }
}
```

核心机制：

- **discriminant（辨识字段）**：每个 union 成员共有的字面量类型字段（`kind`），值必须是唯一字符串或数字字面量。
- **类型收窄**：TypeScript 能通过 `switch`、`if`、`===` 等条件判断，在对应分支里自动推断出具体子类型，不需要手动类型断言。
- **exhaustive check**：`default` 分支把 `s` 赋给 `never` 类型变量，如果有人新增了一个 `Shape` 成员但没加处理逻辑，编译阶段就会报错，防止遗漏。

